+            "columns": {
+                "name": [
+                    { "kind": "utf8", "value": "old" },
+                    { "kind": "utf8", "value": "fresh" },
+                    { "kind": "utf8", "value": "old" }
+                ],
+                "tag": [
+                    { "kind": "utf8", "value": "x" },
+                    { "kind": "utf8", "value": "old" },
+                    { "kind": "utf8", "value": "y" }
+                ]
+            },
+            "column_order": ["name", "tag"]
+        }
+    }))
+    .expect("fixture");
+
+    let expected_result = super::capture_live_oracle_expected(&cfg, &fixture);
